import SwiftUI

struct CoachView: View { @State private var messages:[ChatMessage]=[.init(role:.assistant,text:"هلا أحمد 👋 اسألني عن تمرينك، نومك، جاهزيتك أو تقدمك.")];@State private var input="";@State private var loading=false
    var body:some View{VStack(spacing:0){ScrollViewReader{proxy in ScrollView{LazyVStack(spacing:10){ForEach(messages){m in HStack{if m.role == .user{Spacer()};Text(m.text).padding(12).background(m.role == .user ? Color.cyan.opacity(.2):FitTheme.card,in:RoundedRectangle(cornerRadius:16)).frame(maxWidth:300,alignment:m.role == .user ? .trailing:.leading);if m.role == .assistant{Spacer()}}.id(m.id)}}.padding()}.onChange(of:messages.count){if let id=messages.last?.id{withAnimation{proxy.scrollTo(id,anchor:.bottom)}}}};Divider();HStack{TextField("اكتب للمدرب الذكي…",text:$input,axis:.vertical).textFieldStyle(.roundedBorder);Button{Task{await send()}}label:{Image(systemName:"arrow.up.circle.fill").font(.title)}.disabled(input.trimmingCharacters(in:.whitespacesAndNewlines).isEmpty||loading)}.padding()}.navigationTitle("المدرب الذكي") }
    private func send()async{let q=input.trimmingCharacters(in:.whitespacesAndNewlines);guard !q.isEmpty else{return};input="";messages.append(.init(role:.user,text:q));loading=true;do{let a=try await APIClient.shared.ask(q);messages.append(.init(role:.assistant,text:a))}catch{messages.append(.init(role:.assistant,text:"تعذر الرد: \(error.localizedDescription)"))};loading=false}
}
